在主列表中加一个点击事件onRowClick: this._handlerRowClick,获取该列的数据
_handlerRowClick(row) &#123;    //console.log(row,"-----------")    this.setState(&#123;activity_info:row&#125;)    console.log(this.state.activity_info)    this.setState(&#123;activity_id:row.id&#125;)    this.refs.machine_table.query(&#123;m_id:row.machine_id&#125;)    this.refs.dsc_table.query(&#123;pid:row.id&#125;)&#125;
