多个列表在页面需要多个列表的时候,先写一个表,然后在写另一个表,防止两个表同时写的时候方法混淆.页面请求数据两级联动@PropAction(&#123;auth: false&#125;)async get_region(get,&#123;&#125;)&#123;    	let area = await this.db("jh_machine_region")            .where(&#123;status: 1,type:1&#125;)            .select("name as title", "id as value", "pid as group");        let line = await this.db("jh_machine_region")            .where(&#123;status: 1,type:2&#125;)            .select("name as title", "id as value", "pid as group");        let data=&#123;&#125;        if (area &amp;&amp; line) &#123;            data.area = area;            data.line = line;            this.callback(data);        &#125; else &#123;            this.callback(false, &#123;toast: '数据获取失败！'&#125;)        &#125;&#125;

模糊查找//获取条形码@PropAction(&#123;auth: false&#125;)async get_goods_info(&#123;&#125;, &#123;code&#125;) &#123;    if (code) &#123;        let model = await this.db('jh_machine_product')        .whereRaw(`barcode like ?`, [`%$&#123;code&#125;%`])        .select('name as title', 'id as value', 'price as price')        if (empty(model)) &#123;            this.callback(null, &#123;toast: "没有找到对应商品"&#125;);        &#125; else &#123;            this.callback(model, &#123;toast: "已展示所有商品"&#125;);        &#125;    &#125; else &#123;        this.callback(false, &#123;toast: "请重新输入条形码"&#125;);    &#125;&#125;

传入两个值@PropAction(&#123;auth: false&#125;)async get_machines(&#123;&#125;, &#123;area_id,line_id&#125;) &#123;    if (line_id) &#123;        let model = await this.db("jh_machine")            .where(&#123;line_id:line_id&#125;)            .select('name as title', 'id as value')        console.log(model,'))))))))))))))))')        this.callback(model, &#123;toast: "找到该线路底下所有机器"&#125;);    &#125;else if (area_id) &#123;        let model = await this.db("jh_machine")            .where(&#123;area_id:area_id&#125;)            .select('name as title', 'id as value')        this.callback(model, &#123;toast: "找到该区域底下所有机器"&#125;);    &#125;else&#123;        this.callback(false, &#123;toast: "失败"&#125;);    &#125;&#125;

