下拉框的理解

&lt;Input type="select"    // 方便insert操作数据库,name对应插入字段    name="title"    // input框提示信息    message=&#123;this._lang('product_name')&#125;    // 元素待选择的选项    option=&#123;product_info&#125;    placeholder='请选择'    onValueChange=&#123;(e) =&gt; &#123;        // value        // console.log(e)        if(this.state.product_info) &#123;            // let index=product_info.findIndex(item=&gt; item.value===e)            // 用findIndex获取请求的整个数组中所输入条形码对应的一条数据            product_info = product_info[findIndex(product_info, &#123;"value": e&#125;)]            // console.log(product_info)            // 解决报错undefind和null            if(!empty(this.state.product_info))            this.setState(&#123;                product_price: product_info.price,                product_img: product_info.img,                product_id: product_info.product_id            &#125;)        &#125;    &#125;&#125;/&gt;


