&lt;Input type="text"        name="barcode"        message=&#123;this._lang('barcode')&#125;        placeholder=&#123;"请输入条形码"&#125;        onChange=&#123;(e)=&gt;&#123;            // 设置一个定时器            clearTimeout(this.state.item_timer);            this.setState(&#123;code:e.target.value&#125;);            this.state.item_timer=setTimeout(()=&gt;&#123;                // 发送请求传入code值                this.http1.send(window.SERVER_URL+'/chenxuan/supply/get_goods_info',&#123;code:this.state.code&#125;)                    .success((model)=&gt;&#123;                        console.log(model)                        this.setState(&#123;product_info:model&#125;);                    &#125;)            &#125;,800)        &#125;&#125;/&gt;

