商品分类—多级联动,上传图片


多级联动/*** 多级联动时使用get方法 *///js文件中获取数据@PropAction(&#123;&#125;)async get_level(get, &#123;&#125;) &#123;    // let data = await this.db("jh_machine_product_type")    //     .where(&#123;status: 1&#125;)    //     .select("name as title", "id as value");    // this.callback(data);    let first_level,second_level;    first_level=await this.db("jh_machine_product_type")        .where(&#123;status: 1&#125;)        .select("name as title", "id as value", "pid as group");    second_level=await this.db("jh_machine_product_type")        .where(&#123;status: 1,type : 2&#125;)        .select("name as title", "id as value", "pid as group");    let data=&#123;&#125;    if(first_level &amp;&amp; second_level) &#123;        data.first_level = first_level;        data.second_level = second_level;        this.callback(data);    &#125; else &#123;        this.callback(false, &#123;toast: '数据获取失败，请检查网络！'&#125;)    &#125;&#125;//.jsx文件 接收数据componentDidMount() &#123;    this.http        .send(`$&#123;window.SERVER_URL&#125;/$&#123;this.props.module&#125;/goods/get_level`)        .success((data) =&gt; &#123;        this.setState(&#123;type: data&#125;)    &#125;);&#125;//查询方法//添加方法renderAddDialog() &#123;        let &#123;add&#125; = this.state;        return (            &lt;Directive name="Modal"&gt;                &lt;Dialog                    title=&#123;this._lang('add')&#125;                    ref=&#123;addDialog =&gt; this.addDialog = addDialog&#125;                &gt;                    &lt;div data-fix="buttons"&gt;                        &lt;Button type='submit'&gt;                            &lt;Lang lang="submit"/&gt;                        &lt;/Button&gt;                    &lt;/div&gt;                    &lt;div data-fix="elem"&gt;                        &lt;Form                            onSuccess=&#123;this._handlerAddSuccess&#125;                            action=&#123;this._action('do_add')&#125;                            rules=&#123;valid.goods.do_add&#125;         