let
引入：块级作用域、变量提升、不允许重复命名、暂时性死区

不存在变量提升var命令会发生”变量提升“现象，即变量可以在声明之前使用，值为undefined。按照一般的逻辑，变量应该在声明语句之后才可以使用。为了纠正这种现象，let命令改变了语法行为，它所声明的变量一定要在声明后使用，否则报错。
// var 的情况console.log(foo); // 输出undefinedvar foo = 2;// let 的情况console.log(bar); // 报错ReferenceErrorlet bar = 2;
暂时性死区只要块级作用域内存在let命令，它所声明的变量就“绑定”（binding）这个区域，不再受外部的影响。
if (true) &#123;  // TDZ开始  tmp = 'abc'; // ReferenceError  console.log(tmp); // ReferenceError  let tmp; // TDZ结束  console.log(tmp); // undefined  tmp = 123;  console.log(tmp); // 123&#125;
不允许重复声明let不允许在相同作用域内，重复声明同一个变量。
// 报错function func() &#123;  let a = 10;  var a = 1;&#125;// 报错function func() &#123;  let a = 10;  let a = 1;&#125;
因此，不能在函数内部重新声明参数。
function func(arg) &#123;  let arg; // 报错&#125;function func(arg) &#123;  &#123;    let arg; // 不报错  &#125;&#125;
块级作用域ES5 只有全局作用域和函数作用域，没有块级作用域。let实际上为 JavaScript 新增了块级作用域。
function f1() &#123;  let n = 5;  if (true) &#123;    let n = 10;  &#125;  console.log(n); // 5&#125;
constconst声明一个只读的常量。一旦声明，常量的值就不能改变。也不存在变量提升
const PI = 3.1415;PI // 3.1415PI = 3;// TypeError: Assignment to constant variable.
数组API、对象API、参数结构&lt;!DOCTYPE html&gt;&lt;html lang="en"&gt;&lt;head&gt;  &lt;meta charset="UTF-8"&gt;  &lt;meta name="viewport" content="width=device-width, initial-scale=1.0"&gt;  &lt;title&gt;ES6&lt;/title&gt;&lt;/head&gt;&lt;body&gt;  &lt;script&gt;    // 剩余函数    // 打散数组    let arr = [1, 2, 3, 4, 5, 5, 6]    console.log(...arr)    console.log(Math.max.apply(null, arr))    // 添加元素    function add(...arr)&#123;      let result=arr.reduce(        (prev,elem)=&gt;prev+elem,0      )      console.log(`和为$&#123;result&#125;`)    &#125;    add(1,2,3)    // 拼接数组    let arr1=[0,1,2,3]    let arr2=[4,5,6,7]    // let arr3=[...arr1,...arr2,8,9,10,11]    let arr3=arr1.concat(arr2,8,9,10,11)    console.log(arr3)    // 拼接对象    let obj1=&#123;a:1,b:2&#125;    let obj2=&#123;x:3,y:4&#125;    // let obj3=&#123;...obj1,...obj2&#125;    let obj3=Object.assign(obj1,obj2)    console.log(obj3)    // 参数解构    function order(&#123;zs="鸡腿",xc="薯条",yl="可乐"&#125;)&#123;      console.log(`您的订单：主食：$&#123;zs&#125;，小吃：$&#123;xc&#125;，饮料：$&#123;yl&#125;`)    &#125;    order(&#123;yl:"橙汁"&#125;)    order(&#123;zs:"汉堡包"&#125;)  &lt;/script&gt;&lt;/body&gt;&lt;/html&gt;
