turn new Promise(        function (door) &#123;          console.log(`b起跑了`);          setTimeout(function () &#123;            console.log(`b到达终点`)            door();          &#125;, Math.random() * 1000 + 10)        &#125;      )    &#125;    function cc() &#123;      return new Promise(        function (door) &#123;          console.log(`c起跑了`);          setTimeout(function () &#123;            console.log(`c到达终点`)            door();          &#125;, Math.random() * 1000 + 10)        &#125;      )    &#125;    function dd() &#123;      return new Promise(        function (door) &#123;          console.log(`d起跑了`);          setTimeout(function () &#123;            console.log(`d到达终点`)            door();          &#125;, Math.random() * 1000 + 10)        &#125;      )    &#125;    // 调用的时候：return new Promise()提供.then勾住后面的任务    aa().then(bb).then(cc).then(dd).then(()=&gt;console.log("结束"))  &lt;/script&gt;&lt;/body&gt;&lt;/html&gt;

